37: /**
38:  * A vanilla FX option, resolved for pricing.
39:  * <p>
40:  * This is the resolved form of {@link FxVanillaOption} and is an input to the pricers.
41:  * Applications will typically create a {@code ResolvedFxVanillaOption} from a {@code FxVanillaOption}
42:  * using {@link FxVanillaOption#resolve(ReferenceData)}.
43:  * <p>
44:  * A {@code ResolvedFxVanillaOption} is bound to data that changes over time, such as holiday calendars.
45:  * If the data changes, such as the addition of a new holiday, the resolved form will not be updated.
46:  * Care must be taken when placing the resolved form in a cache or persistence layer.
47:  */
48: @BeanDefinition
49: public final class ResolvedFxVanillaOption
50:     implements ResolvedProduct, ImmutableBean, Serializable {
51: 
52:   /**
53:    * Whether the option is long or short.
54:    * <p>
55:    * At expiry, the long party will have the option to enter in this transaction; 
56:    * the short party will, at the option of the long party, potentially enter into the inverse transaction.
57:    */
58:   @PropertyDefinition(validate = "notNull")
59:   private final LongShort longShort;
60:   /**
61:    * The expiry date-time of the option.
62:    * <p>
63:    * The option is European, and can only be exercised on the expiry date.
64:    */
65:   @PropertyDefinition(validate = "notNull")
66:   private final ZonedDateTime expiry;
67:   /**
68:    * The underlying foreign exchange transaction.
69:    * <p>
70:    * At expiry, if the option is in the money, this foreign exchange will occur.
71:    * A call option permits the transaction as specified to occur.
72:    * A put option permits the inverse transaction to occur.
73:    */
74:   @PropertyDefinition(validate = "notNull")
75:   private final ResolvedFxSingle underlying;
76: 
77:   //-------------------------------------------------------------------------
78:   @ImmutableValidator
79:   private void validate() {
80:     inOrderOrEqual(expiry.toLocalDate(), underlying.getPaymentDate(), "expiry.date", "underlying.paymentDate");
81:   }
82: 
83:   //-------------------------------------------------------------------------
84:   /**
85:    * Gets currency pair of the base currency and counter currency.
86:    * <p>
87:    * This currency pair is conventional, thus indifferent to the direction of FX.
88:    * 
89:    * @return the currency pair
90:    */
91:   public CurrencyPair getCurrencyPair() {
92:     return underlying.getCurrencyPair();
93:   }
94: 
95:   /**
96:    * Gets the expiry date of the option.
97:    * 
98:    * @return the expiry date
99:    */
100:   public LocalDate getExpiryDate() {
101:     return expiry.toLocalDate();
102:   }
103: 
104:   /**
105:    * Gets the strike rate.
106:    * 
107:    * @return the strike
108:    */
109:   public double getStrike() {
110:     return Math.abs(underlying.getCounterCurrencyPayment().getAmount() /
111:         underlying.getBaseCurrencyPayment().getAmount());
112:   }
113: 
114:   /**
115:    * Returns the put/call flag.
116:    * <p>
117:    * This is the put/call for the base currency.
118:    * If the amount for the base currency is positive, the option is a call on the base currency (put on counter currency). 
119:    * If the amount for the base currency is negative, the option is a put on the base currency (call on counter currency).
120:    * 
121:    * @return the put or call
122:    */
123:   public PutCall getPutCall() {
124:     return underlying.getCounterCurrencyPayment().getAmount() > 0d ? PutCall.PUT : PutCall.CALL;
125:   }
126: 
127:   /**
128:    * Get the counter currency of the underlying FX transaction.
129:    * 
130:    * @return the counter currency
131:    */
132:   public Currency getCounterCurrency() {
133:     return underlying.getCounterCurrencyPayment().getCurrency();
134:   }
